// Dos formas de especificar una regla
// Tool ← bloquea/permite toda invocación de la herramienta
// Tool(especificador) ← bloquea/permite solo invocaciones que coincidan

Bash              // todas las invocaciones de Bash
Bash(npm run build)  // exactamente ese comando
Bash(npm run *)      // cualquier npm run ...
Read(.env)           // leer cualquier .env en cualquier nivel
Read(/src/**/*.ts)   // leer .ts bajo /src/ relativo a project root
WebFetch(domain:api.example.com)  // fetch solo a ese dominio

// El * en reglas de Bash coincide con cualquier secuencia, incluyendo espacios
"Bash(npm run *)"      // npm run build, npm run test, npm run dev...
"Bash(* --version)"    // node --version, python --version...
"Bash(git * main)"     // git checkout main, git merge main...

// Diferencia crítica: espacio antes del *
"Bash(ls *)"   // ✓ ls -la  ✗ lsof  ← word boundary por el espacio
"Bash(ls*)"    // ✓ ls -la  ✓ lsof  ← sin boundary

// El :* al final es equivalente al espacio + *
"Bash(ls:*)"   // equivalente a "Bash(ls *)"

// El prefijo del path determina el punto de anclaje:
//   //path  → ruta absoluta desde raíz del filesystem
//   ~/path  → relativo al home directory
//   /path   → relativo al project root
//   path    → relativo al directorio actual

Read(//Users/alice/.ssh/**)  // absoluta — doble barra
Read(~/.zshrc)               // home
Edit(/src/**/*.ts)           // project root
Read(*.env)                  // directorio actual

// .env es especial: coincide a cualquier profundidad
Read(.env)      // equivalente a Read(**/.env)
Read(//**/.env) // cualquier .env en todo el filesystem

// ⚠️ Trampa: Read(/Users/alice/file) NO es absoluta
// Es relativa al project root. Para absoluta: Read(//Users/alice/file)

{
  "defaultMode": "default",
  "permissions": {
    "allow": [
      "Bash(npm run *)",
      "Bash(git commit *)",
      "Bash(* --version)",
      "WebFetch(domain:api.github.com)"
    ],
    "ask": [
      "Bash(git push *)"
    ],
    "deny": [
      "Bash(rm -rf *)",
      "Bash(curl *)",
      "Read(//**/.env)"
    ]
  }
}

{
  "defaultMode": "dontAsk",
  "permissions": {
    "allow": [
      "Read",
      "Bash(ls *)", "Bash(find * -type f)",
      "Bash(grep *)", "Bash(cat *)",
      "Bash(git log *)", "Bash(git diff *)", "Bash(git status)"
    ],
    "deny": [
      "Edit", "Write",
      "Bash(git commit *)", "Bash(git push *)",
      "Bash(rm *)", "Bash(curl *)", "Bash(wget *)"
    ]
  }
}

{
  "permissions": {
    "allow": [
      "mcp__github__create_issue",
      "mcp__github__list_issues",
      "Agent(Explore)"
