{
  "sandbox": {
    "enabled": true,
    "autoAllowBashIfSandboxed": true,
    "failIfUnavailable": false,
    "allowUnsandboxedCommands": true,
    "filesystem": {
      "allowWrite": ["~/.kube", "/tmp"],
      "denyWrite": ["~/.ssh"],
      "denyRead": ["~/.ssh", "~/.aws"],
      "allowRead": ["."]
    },
    "network": {
      "allowedDomains": [
        "registry.npmjs.org",
        "api.github.com"
      ],
      "deniedDomains": ["internal.corp.com"]
    },
    "excludedCommands": ["docker", "watchman"]
  }
}
